func:
msg.review = {
  workflow: 'deep-review-freeform:v1',
  target: {
    kind: 'github_pr',
    owner: 'getlarge',
    repo: 'themoltnet',
    prNumber: 1486,
    baseRef: 'main',
    headRef: 'issue-1481-review-fixes'
  },
  dimensions: [
    'correctness',
    'security',
    'performance',
    'dry-codebase-fit',
    'design-api-backcompat',
    'tests',
    'operability',
    'readability'
  ],
  publishPolicy: 'none',
  sizeGate: { maxFiles: 25, maxLoc: 1500 },
  memory: {
    query: 'task artifacts node-red review workflow branch issue-1481-review-fixes',
    tags: ['decision'],
    limit: 8
  }
};
msg.payload = {
  query: msg.review.memory.query,
  tags: msg.review.memory.tags,
  limit: msg.review.memory.limit
};
return msg;

const entries = Array.isArray(msg.payload) ? msg.payload : [];
msg.reviewMemory = entries.map((entry) => ({
  id: entry.id,
  title: entry.title || '',
  type: entry.entryType || entry.type || '',
  tags: entry.tags || [],
  summary: String(entry.content || entry.summary || '').slice(0, 700)
}));
return msg;

const artifacts = Array.isArray(msg.payload)
  ? msg.payload
  : Array.isArray(msg.artifacts?.page?.artifacts)
    ? msg.artifacts.page.artifacts
    : [];
const preferred = artifacts.find((artifact) =>
  artifact.title === 'review-bundle' ||
  artifact.title === 'review-bundle.json' ||
  artifact.title === 'review.patch' ||
  artifact.title === 'patch.diff' ||
  artifact.kind === 'review-bundle' ||
  artifact.kind === 'review-patch'
);
if (!preferred) {
  node.status({ fill: 'yellow', shape: 'ring', text: `no bundle artifact (${artifacts.length})` });
  return null;
}
msg.payload = { artifact: preferred, cid: preferred.cid };
msg.cid = preferred.cid;
msg.attemptN = preferred.attemptN;
msg.reviewBundleArtifact = preferred;
return msg;

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || {};
msg.reviewBundle = msg.result?.artifactBody || msg.payload || {};
msg.reviewBundleRef = msg.result?.artifactRef || msg.result?.outputRef || null;
msg.review.freezeTaskId = msg.freezeSnapshot?.taskId || msg.result?.outputRef?.taskId || null;
msg.review.freezeAttemptN = msg.freezeSnapshot?.acceptedAttemptN || msg.freezeSnapshot?.attempt?.attemptN || null;
msg.taskId = msg.review.freezeTaskId;
msg.attemptN = msg.review.freezeAttemptN;
state.correlationId = msg.correlationId;
state.review = msg.review;
state.reviewBundle = msg.reviewBundle;
state.reviewBundleRef = msg.reviewBundleRef;
state.freezeSnapshot = msg.freezeSnapshot || null;
state.tasks = state.tasks || {};
state.tasks.freeze = { taskId: msg.review.freezeTaskId, attemptN: msg.review.freezeAttemptN };
state.specialistResults = state.specialistResults || [];
flow.set(key, state);
msg.reviewState = state;
return msg;

msg.payload = {
  taskType: 'freeform',
  title: 'Deep review: preflight',
  tags: ['deep-review', 'deep-review:preflight', msg.review.workflow],
  correlationId: msg.correlationId,
  input: {
    brief: [
      'Run the design preflight for this deep review.',
      '',
      'Decide whether the approach is sound before line-level review.',
      'Return a freeform artifact with kind "json" and title "preflight".',
      '',
      'The artifact body must be JSON:',
      '{ "verdict": "PROCEED|PIVOT", "summary": "...", "questions": [], "pivotSize": "small|medium|large|null", "recommendedNextStep": "..." }',
      '',
      'Use PROCEED when line-level specialist review should continue, even if the scope is large. Use PIVOT only when the approach is materially wrong, not when you merely prefer another implementation.',
      '',
      'If the submit tool requires a verification block, every verification.results[].kind must be one of: gate, assertion, rubric, sideEffect. For a submit-tool-call success criterion, report it as kind "gate"; never use "submit-tool-call" as a verification result kind.'
    ].join('\n'),
    expectedOutput: 'Summary plus artifact kind=json title=preflight with verdict PROCEED or PIVOT.',
    constraints: ['Do not produce line-level findings.', 'Do not modify code.', 'Choose PROCEED or PIVOT.', 'When self-verifying a submit-tool-call gate, use verification result kind "gate".'],
    context: [
      { slug: 'review-config', binding: 'context_inline', content: JSON.stringify(msg.review, null, 2) },
      { slug: 'review-bundle', binding: 'context_inline', content: JSON.stringify(msg.reviewBundle, null, 2) },
      { slug: 'review-bundle-ref', binding: 'context_inline', content: JSON.stringify(msg.reviewBundleRef, null, 2) }
    ],
    execution: { workspace: 'shared_mount' }
  }
};
return msg;

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || {};
msg.preflight = msg.result?.artifactBody || msg.payload || {};
msg.preflight.verdict = String(msg.preflight.verdict || 'PROCEED').toUpperCase();
state.correlationId = msg.correlationId;
state.review = state.review || msg.review;
state.reviewBundle = state.reviewBundle || msg.reviewBundle;
state.reviewBundleRef = state.reviewBundleRef || msg.reviewBundleRef;
state.preflight = msg.preflight;
state.preflightRef = msg.result?.artifactRef || msg.result?.outputRef || null;
state.tasks = state.tasks || {};
state.tasks.preflight = { taskId: msg.result?.outputRef?.taskId || msg.payload?.taskId || null };
flow.set(key, state);
msg.reviewState = state;
return msg;

msg.payload = {
  taskType: 'freeform',
  title: 'Deep review: publish pivot report',
  tags: ['deep-review', 'deep-review:pivot', msg.review.workflow],
  correlationId: msg.correlationId,
  input: {
    brief: 'Prepare the preflight PIVOT result as a final design review artifact. Do not add line-level findings. If publishPolicy is not none and required credentials/tools are available, publish according to policy; otherwise only return the artifact. If the submit tool requires verification, use verification result kind "gate" for any submit-tool-call success criterion; never use "submit-tool-call" as verification.results[].kind.',
    expectedOutput: 'Summary plus artifact kind=markdown title=design-review.',
    constraints: ['When self-verifying a submit-tool-call gate, use verification result kind "gate".'],
    context: [
      { slug: 'review-config', binding: 'context_inline', content: JSON.stringify(msg.review, null, 2) },
      { slug: 'review-bundle', binding: 'context_inline', content: JSON.stringify(msg.reviewBundle, null, 2) },
      { slug: 'preflight', binding: 'context_inline', content: JSON.stringify(msg.preflight, null, 2) }
    ],
    execution: { workspace: 'none' }
  }
};
return msg;

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || {};
state.correlationId = msg.correlationId;
state.review = state.review || msg.review;
state.reviewBundle = state.reviewBundle || msg.reviewBundle;
state.reviewBundleRef = state.reviewBundleRef || msg.reviewBundleRef;
state.preflight = state.preflight || msg.preflight;
state.dimensions = [...((state.review || msg.review).dimensions || [])];
state.pendingDimensions = [];
state.expectedSpecialists = state.dimensions.length;
state.completedSpecialists = 0;
state.aggregateStarted = false;
state.specialistResults = [];
state.tasks = state.tasks || {};
state.tasks.specialists = {};
flow.set(key, state);
msg.reviewState = state;
msg.pendingDimensions = [];
msg.specialistResults = state.specialistResults;
if (state.dimensions.length === 0) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'no dimensions' });
  return [null, msg];
}
node.status({ fill: 'blue', shape: 'dot', text: `fan out ${state.dimensions.length}` });
const messages = state.dimensions.map((dimension, index) => ({
  ...msg,
  reviewDimension: dimension,
  payload: { dimension, index, total: state.dimensions.length }
}));
return [messages, null];

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || msg.reviewState || {};
const expected = Number(state.expectedSpecialists || state.dimensions?.length || 0);
const completed = Array.isArray(state.specialistResults) ? state.specialistResults.length : 0;
state.completedSpecialists = completed;
flow.set(key, state);
msg.reviewState = state;
msg.review = state.review || msg.review;
msg.reviewBundle = state.reviewBundle || msg.reviewBundle;
msg.reviewBundleRef = state.reviewBundleRef || msg.reviewBundleRef;
msg.preflight = state.preflight || msg.preflight;
msg.specialistResults = state.specialistResults || [];
msg.pendingDimensions = [];
if (expected === 0) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'no specialist dimensions' });
  return msg;
}
if (completed < expected) {
  node.status({ fill: 'blue', shape: 'dot', text: `${completed}/${expected} specialist(s)` });
  return null;
}
if (state.aggregateStarted) {
  node.status({ fill: 'grey', shape: 'ring', text: 'aggregate already started' });
  return null;
}
state.aggregateStarted = true;
state.aggregateReadyAt = new Date().toISOString();
flow.set(key, state);
msg.reviewState = state;
node.status({ fill: 'green', shape: 'dot', text: `${completed}/${expected} complete` });
return msg;

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || msg.reviewState || {};
const dimension = msg.payload.dimension || state.currentDimension;
msg.reviewDimension = dimension;
msg.review = state.review || msg.review;
msg.reviewBundle = state.reviewBundle || msg.reviewBundle;
msg.reviewBundleRef = state.reviewBundleRef || msg.reviewBundleRef;
msg.preflight = state.preflight || msg.preflight;
msg.payload = {
  taskType: 'freeform',
  title: 'Deep review: ' + dimension,
  tags: ['deep-review', 'deep-review:specialist', 'dimension:' + dimension, msg.review.workflow],
  correlationId: msg.correlationId,
  input: {
    brief: [
      'Run one specialist pass for a deep review workflow.',
      '',
      'Dimension: ' + dimension,
      '',
      'Use only this lens. Ignore unrelated concerns, formatter/lint noise, and personal preference.',
      'Read the review bundle and inspect surrounding code as needed. If artifact download tools are available, use the bundle CIDs for the patch/file list. Otherwise use the inline bundle metadata to fetch the same target.',
      '',
      'Return a freeform artifact with kind "json" and title "specialist-findings". The body must be JSON with fields: dimension, findings, clean, coverageNotes.',
      'Each finding must include: severity, path, line, problem, why, fixDirection.',
      '',
      'If the submit tool requires a verification block, every verification.results[].kind must be one of: gate, assertion, rubric, sideEffect. For a submit-tool-call success criterion, report it as kind "gate"; never use "submit-tool-call" as a verification result kind.'
    ].join('\n'),
    expectedOutput: 'Summary plus artifact kind=json title=specialist-findings.',
    constraints: ['Do not modify code.', 'Findings only; no broad summary unless clean.', 'When self-verifying a submit-tool-call gate, use verification result kind "gate".'],
    context: [
      { slug: 'review-config', binding: 'context_inline', content: JSON.stringify(msg.review, null, 2) },
      { slug: 'review-bundle', binding: 'context_inline', content: JSON.stringify(msg.reviewBundle, null, 2) },
      { slug: 'review-bundle-ref', binding: 'context_inline', content: JSON.stringify(msg.reviewBundleRef, null, 2) },
      { slug: 'preflight', binding: 'context_inline', content: JSON.stringify(msg.preflight, null, 2) }
    ],
    execution: { workspace: 'shared_mount' }
  }
};
return msg;

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || msg.reviewState || {};
const result = {
  dimension: msg.reviewDimension || msg.payload?.dimension || state.currentDimension,
  output: msg.payload,
  artifact: msg.result?.artifact || null,
  artifactBody: msg.result?.artifactBody || null,
  artifactRef: msg.result?.artifactRef || null,
  outputRef: msg.result?.outputRef || null
};
state.specialistResults = Array.isArray(state.specialistResults) ? state.specialistResults : [];
state.specialistResults = state.specialistResults.filter((item) => item.dimension !== result.dimension);
state.specialistResults.push(result);
state.tasks = state.tasks || {};
state.tasks.specialists = state.tasks.specialists || {};
state.tasks.specialists[result.dimension] = {
  taskId: result.outputRef?.taskId || msg.payload?.id || null,
  outputCid: result.outputRef?.outputCid || null,
  artifactCid: result.artifactRef?.artifactCid || result.artifact?.cid || null
};
state.completedSpecialists = state.specialistResults.length;
flow.set(key, state);
msg.reviewState = state;
msg.review = state.review || msg.review;
msg.reviewBundle = state.reviewBundle || msg.reviewBundle;
msg.reviewBundleRef = state.reviewBundleRef || msg.reviewBundleRef;
msg.preflight = state.preflight || msg.preflight;
msg.specialistResults = state.specialistResults;
msg.pendingDimensions = [];
msg.payload = null;
return msg;

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || msg.reviewState || {};
const payload = msg.payload && typeof msg.payload === 'object' ? msg.payload : {};
const tags = Array.isArray(payload.tags) ? payload.tags : [];
const dimensionTag = tags.find((tag) => typeof tag === 'string' && tag.startsWith('dimension:'));
const dimension = msg.reviewDimension || payload.dimension || (typeof dimensionTag === 'string' ? dimensionTag.slice('dimension:'.length) : null);
if (!dimension) {
  node.status({ fill: 'red', shape: 'ring', text: 'missing dimension' });
  return null;
}
const error = msg.error || {};
const result = {
  dimension,
  status: 'failed',
  output: null,
  artifact: null,
  artifactBody: {
    dimension,
    findings: [],
    clean: false,
    coverageNotes: 'Specialist task failed before readable findings were available.',
    failed: true,
    error: {
      message: String(error.message || 'specialist lane failed'),
      source: error.source || null
    }
  },
  artifactRef: null,
  outputRef: null,
  error: {
    message: String(error.message || 'specialist lane failed'),
    source: error.source || null
  }
};
state.specialistResults = Array.isArray(state.specialistResults) ? state.specialistResults : [];
state.specialistResults = state.specialistResults.filter((item) => item.dimension !== dimension);
state.specialistResults.push(result);
state.tasks = state.tasks || {};
state.tasks.specialists = state.tasks.specialists || {};
state.tasks.specialists[dimension] = {
  status: 'failed',
  taskId: payload.id || null,
  error: result.error
};
state.completedSpecialists = state.specialistResults.length;
flow.set(key, state);
msg.reviewState = state;
msg.review = state.review || msg.review;
msg.reviewBundle = state.reviewBundle || msg.reviewBundle;
msg.reviewBundleRef = state.reviewBundleRef || msg.reviewBundleRef;
msg.preflight = state.preflight || msg.preflight;
msg.specialistResults = state.specialistResults;
msg.pendingDimensions = [];
msg.payload = null;
node.status({ fill: 'yellow', shape: 'ring', text: `${dimension} failed` });
return msg;

const key = 'deepReview:' + msg.correlationId;
const state = flow.get(key) || msg.reviewState || {};
msg.review = state.review || msg.review;
msg.reviewBundle = state.reviewBundle || msg.reviewBundle;
msg.preflight = state.preflight || msg.preflight;
msg.specialistResults = state.specialistResults || msg.specialistResults || [];
state.aggregateRequestedAt = new Date().toISOString();
flow.set(key, state);
msg.reviewState = state;
msg.payload = {
  taskType: 'freeform',
  title: 'Deep review: aggregate findings',
  tags: ['deep-review', 'deep-review:aggregate', msg.review.workflow],
  correlationId: msg.correlationId,
  input: {
    brief: [
      'Aggregate the specialist deep-review results into one final review.',
      '',
      'Dedupe findings, keep the highest severity, rank globally, surface themes, and check whether any changed files in the review bundle were not covered.',
      '',
      'Some specialist results may have status "failed" with an error instead of findings. Treat those as coverage gaps, include them in the final review summary, and do not invent findings for failed dimensions.',
      '',
      'Return a freeform artifact with kind "markdown" and title "final-review". Also include a compact kind "json" artifact titled "review-summary" with fields: verdict, topRisks, findingCounts, coverage.',
      '',
      'If the submit tool requires a verification block, every verification.results[].kind must be one of: gate, assertion, rubric, sideEffect. For a submit-tool-call success criterion, report it as kind "gate"; never use "submit-tool-call" as a verification result kind.'
    ].join('\n'),
    expectedOutput: 'Summary plus artifacts markdown/final-review and json/review-summary.',
    constraints: ['Do not modify code.', 'Do not publish externally unless publishPolicy requires a separate publish task.', 'When self-verifying a submit-tool-call gate, use verification result kind "gate".'],
    context: [
      { slug: 'review-config', binding: 'context_inline', content: JSON.stringify(msg.review, null, 2) },
      { slug: 'review-bundle', binding: 'context_inline', content: JSON.stringify(msg.reviewBundle, null, 2) },
      { slug: 'preflight', binding: 'context_inline', content: JSON.stringify(msg.preflight, null, 2) },
      { slug: 'specialist-results', binding: 'context_inline', content: JSON.stringify(msg.specialistResults, null, 2) },
      { slug: 'review-run-state', binding: 'context_inline', content: JSON.stringify({ correlationId: state.correlationId, tasks: state.tasks, dimensions: state.dimensions }, null, 2) }
    ],
    execution: { workspace: 'none' }
  }
};
return msg;

const key = 'deepReview:' + (msg.correlationId || 'unknown');
const state = flow.get(key) || msg.reviewState || {};
const snapshot = msg.payload && typeof msg.payload === 'object' ? msg.payload : {};
const task = snapshot.task || {};
const attempt = snapshot.attempt || {};
const stage = msg.reviewStage || task.title || task.taskType || msg.error?.source?.name || 'deep-review';
const error = snapshot.error || attempt.error || msg.error || { message: stage + ' failed' };
state.correlationId = msg.correlationId || state.correlationId || null;
state.review = state.review || msg.review || null;
state.failed = true;
state.failure = {
  stage,
  taskId: snapshot.taskId || task.id || msg.taskId || null,
  attemptN: snapshot.acceptedAttemptN || attempt.attemptN || msg.attemptN || null,
  error: {
    message: String(error.message || error.detail || error || 'deep review stage failed'),
    source: error.source || null
  },
  failedAt: new Date().toISOString()
};
flow.set(key, state);
msg.reviewState = state;
msg.payload = {
  workflowStatus: 'failed',
  correlationId: state.correlationId,
  stage,
  failure: state.failure
};
node.status({ fill: 'red', shape: 'ring', text: stage + ' failed' });
return msg;

const key = 'deepReview:' + (msg.correlationId || 'unknown');
const state = flow.get(key) || msg.reviewState || {};
const snapshot = msg.payload && typeof msg.payload === 'object' ? msg.payload : {};
const task = snapshot.task || {};
const attempt = snapshot.attempt || {};
const stage = msg.reviewStage || task.title || task.taskType || msg.error?.source?.name || 'deep-review';
const error = snapshot.error || attempt.error || msg.error || { message: stage + ' failed' };
state.correlationId = msg.correlationId || state.correlationId || null;
state.review = state.review || msg.review || null;
state.failed = true;
state.failure = {
  stage,
  taskId: snapshot.taskId || task.id || msg.taskId || null,
  attemptN: snapshot.acceptedAttemptN || attempt.attemptN || msg.attemptN || null,
  error: {
    message: String(error.message || error.detail || error || 'deep review stage failed'),
    source: error.source || null
  },
  failedAt: new Date().toISOString()
};
flow.set(key, state);
msg.reviewState = state;
msg.payload = {
  workflowStatus: 'failed',
  correlationId: state.correlationId,
  stage,
  failure: state.failure
};
node.status({ fill: 'red', shape: 'ring', text: stage + ' failed' });
return msg;
